sql:
SELECT apartment_no, apartment_category, cost
FROM apartments
WHERE apartment_category = 'S' AND cost > '500000';

SELECT
  (SELECT COUNT(*) FROM purchasers) AS purchaser_count,
  (SELECT COUNT(*) FROM users WHERE role = 'sales agent') AS sales_agent_count;

external_knowledge:
- "Cozy nests" refers to apartments;
- "Bustling city of Los Angeles" refers to the city of Los Angeles;
- "Open for the taking" refers to apartments that are available for sale;
- "Price tag" refers to the cost of the apartments;
- "Soars above half a million dollars" means the average cost is greater than $500,000.

- 'Available' status in the `apartment_availability` table indicates that the apartment is currently available for sale;
- 'NULL' sale date in the `sales` table means the apartment has not been sold;
- The apartment categories 'D' and 'S' refer to Delux and SuperDelux, respectively.

- 'SuperDelux' apartments are a category of high-end apartments;
- 'blooming and ready to be picked' refers to apartments that are currently available for purchase;
- 'more than two bedrooms' indicates the minimum number of bedrooms required.

- "completed sale" refers to a sale where the `status` column in the `sales` table is set to 'completed';
- "average rating" is the mean of all ratings given to an apartment in the `apartment_reviews` table;
- "most recent" refers to the latest date in the `sale_date` column.

sql:
SELECT COUNT(apartment_id) 
FROM apartment_availability 
WHERE status = 'available';

SELECT feature_name
FROM apartment_features
WHERE feature_type = 'amenity';

external_knowledge:
- 'Largest deluxe apartments' refers to the apartments with the highest square footage in each location;
- 'Deluxe apartments' are those with the category 'D';
- 'Generated more than $50,000 in commissions' means the total commission from sales of these apartments exceeds $50,000.

- 'completed' status in the `sales` table indicates that the sale has been finalized;
- 'average rating' is computed from the `apartment_reviews` table for apartments with completed sales;
- 'top 3' refers to the highest-ranked apartments based on their average ratings.

- "highest-priced apartment" refers to the apartment with the highest sale price in each category;
- "total sales across all categories" is the sum of all sale prices for all apartments;
- "contributing to more than half" means the total sales of the selected categories are greater than 50% of the total sales.

- 'Completed sales' refer to transactions where the status is marked as 'completed';
- 'Sale ratio' is calculated as the number of completed sales divided by the total number of sales transactions for each apartment;
- 'Apartment category' includes 'D' for Delux and 'S' for SuperDelux;
- 'Location details' include the name, city, state, and country of the apartment's location.

sql:
SELECT apartment_category 
FROM apartments 
WHERE apartment_id NOT IN (SELECT apartment_id FROM sales);

external_knowledge:
- 'Cozy nests' refers to apartments;
- 'Adorned with more than one gem' means having more than one feature;
- 'Categorized as Delux' refers to the apartment category 'D';
- 'Exactly 2 bedrooms' means the apartment has 2 bedrooms.

- "shining stars in the real estate sky" refers to apartments available for sale;
- "have a gym" refers to apartments with a gym feature;
- "perfect score from their verified admirers" refers to a verified review rating of 5.

- 'SuperDelux' is a category of apartments that typically offer premium features and amenities;
- The year 2022 refers to the calendar year from January 1 to December 31;
- 'Available' and 'sold' refer to the time periods during which the apartment was listed as available and when it was sold, respectively.

- The categories of apartments are 'D' for Delux and 'S' for SuperDelux;
- The rating scale is from 1 to 5, with 5 being the highest;
- The total sales amount is the sum of the sale prices for each category;
- The average rating is the mean of all ratings for each category;
- The number of reviews is the count of unique review IDs for each category.

- 'Most expensive' refers to the highest cost within each apartment category;
- 'Most recent' refers to the latest review date;
- 'Verified purchase' indicates the review is from a verified purchaser.

- 'Delux' apartments are a specific category of apartments, typically more luxurious or higher-end;
- 'New York' refers to the city where the apartments are located;
- 'Completed' sales indicate that the transactions have been finalized.

- "Adorned with at least one image" means the apartment has at least one associated image;
- "Nestled in the heart of Los Angeles" means the apartment is located in Los Angeles;
- "Ready to welcome you on the first of October" means the apartment is available on October 1, 2023.

- "adorned with a bouquet of features" refers to the concatenation of all features associated with an apartment;
- "record of sales" includes the total sales amount and the number of sales transactions;
- "availability" refers to the number of availability records;
- "images" refers to the number of images associated with each apartment.

sql:
SELECT apartment_category, cost
FROM apartments
ORDER BY apartment_category ASC;

SELECT available_from, status
FROM apartment_availability
ORDER BY available_from ASC;

external_knowledge:
- 'Delux' refers to a specific category of apartments;
- 'available_to > '2023-12-31'' means the apartment is available for sale after December 31, 2023;
- 'status = 'available'' indicates that the apartment is currently on the market.

- "stars of the real estate show" refers to purchasers who have bought apartments with the highest ratings;
- "shining brightly" implies that the apartments have a rating of 4 or higher;
- "top-rated apartments" indicates that the highest rating for each purchaser is selected.

- 'Apartment features' include amenities like a pool or gym;
- 'Sales performance' includes metrics such as the total number of sales, average sale price, and the number of completed sales;
- 'Customer reviews' are represented by the average rating and the total number of reviews.
